[AUDIT-R3 MEDIUM FIX] Store snapshot view specification.

Per spec/01-store.md §1.5.2:

  impl Store {
      /// Current view: all asserted datoms minus retracted ones.
      /// This is the 'live' state of the store.
      pub fn current(&self) -> StoreView {
          StoreView {
              store: self,
              as_of: None,  // no time bound → all transactions
          }
      }

      /// Historical view: state as of a specific transaction.
      /// Only includes datoms from transactions ≤ tx_id.
      pub fn as_of(&self, tx_id: TxId) -> StoreView {
          StoreView {
              store: self,
              as_of: Some(tx_id),
          }
      }
  }

  pub struct StoreView<'a> {
      store: &'a Store,
      as_of: Option<TxId>,
  }

  impl<'a> StoreView<'a> {
      /// Iterate datoms in this view
      pub fn datoms(&self) -> impl Iterator<Item = &Datom> {
          self.store.datoms().filter(|d| {
              // Time filter
              if let Some(cutoff) = self.as_of {
                  if d.tx.total_order() > cutoff.total_order() { return false; }
              }
              // Retraction filter for current view
              if d.op == Op::Assert {
                  !self.is_retracted(d)
              } else {
                  false  // don't return retraction datoms in view
              }
          })
      }

      fn is_retracted(&self, datom: &Datom) -> bool {
          self.store.eavt_range(datom.entity, datom.attribute)
              .any(|d| d.op == Op::Retract
                  && d.value == datom.value
                  && d.tx.total_order() > datom.tx.total_order()
                  && self.as_of.map_or(true, |cutoff| d.tx.total_order() <= cutoff.total_order()))
      }
  }

KEY PROPERTY: current() is the 'default' view — it's what queries see.
as_of() enables time-travel queries (query the store as it was at any point).

V:TYPE — StoreView compiles with lifetime 'a
V:PROP — current() never returns retracted datoms
V:PROP — as_of(genesis_tx) returns only genesis datoms

[AUDIT-R3 MEDIUM FIX] STORE Kani bounded model checking.

Kani harnesses for bounded verification of STORE invariants:

  #[cfg(kani)]
  mod kani_proofs {
      use super::*;

      // Harness 1: Append-only guarantee (INV-STORE-001)
      #[kani::proof]
      #[kani::unwind(10)]
      fn verify_append_only() {
          let mut store = Store::genesis();
          let n_before = store.datom_count();
          let tx = kani::any::<Transaction<Building>>();
          if let Ok(committed) = tx.commit(&store) {
              let _ = committed.apply(&mut store);
          }
          kani::assert(store.datom_count() >= n_before, 'datom count must not decrease');
      }

      // Harness 2: HLC monotonicity
      #[kani::proof]
      #[kani::unwind(5)]
      fn verify_hlc_monotone() {
          let mut hlc = Hlc::new(AgentId::test());
          let t1 = hlc.tick();
          let t2 = hlc.tick();
          kani::assert(t2.total_order() > t1.total_order(), 'HLC must be monotone');
      }

      // Harness 3: Merge commutativity (bounded)
      #[kani::proof]
      #[kani::unwind(8)]
      fn verify_merge_commutative() {
          let a = kani::any::<Store>(); // bounded to ≤ 3 datoms
          let b = kani::any::<Store>();
          let ab = merge(&a, &b);
          let ba = merge(&b, &a);
          kani::assert(ab.store == ba.store, 'merge must be commutative');
      }

      // Harness 4: Content-addressable identity
      #[kani::proof]
      fn verify_content_addressable() {
          let d1 = kani::any::<Datom>();
          let d2 = Datom { ..d1.clone() };
          kani::assert(d1 == d2, 'identical content → identical datom');
      }
  }

KANI TIERS (per guide/10-verification.md):
  Fast (PRs): unwind ≤ 5, runs in < 2 min
  Nightly: unwind ≤ 20, runs in < 30 min
  Weekly (extended): unwind ≤ 50, runs in < 2 hours

V:KANI — all 4 harnesses verify successfully at fast tier

[AUDIT-R3 MEDIUM FIX] Content-addressed writer specification.

Per spec/01b-storage-layout.md §1b.4:

  pub fn write_tx_file(
      layout: &DiskLayout,
      tx: &Transaction<Applied>,
  ) -> Result<PathBuf, BraidError> {
      // 1. Serialize transaction datoms to canonical EDN
      let edn_bytes = canonical_edn_serialize(&tx.datoms());

      // 2. Compute content hash
      let hash = blake3::hash(&edn_bytes);
      let filename = format\!('tx_{}.edn', base58_encode(hash.as_bytes()));

      // 3. Write atomically using O_CREAT|O_EXCL
      let path = layout.tx_dir().join(&filename);
      let temp_path = layout.temp_dir().join(&format\!('.tmp_{}', filename));

      // Write to temp file first
      std::fs::write(&temp_path, &edn_bytes)
          .map_err(BraidError::Io)?;

      // Atomic rename (same filesystem guaranteed)
      match std::fs::rename(&temp_path, &path) {
          Ok(()) => Ok(path),
          Err(e) if e.kind() == std::io::ErrorKind::AlreadyExists => {
              // Content-addressable: file already exists with same content
              std::fs::remove_file(&temp_path).ok();
              Ok(path)  // idempotent success
          }
          Err(e) => Err(BraidError::Io(e)),
      }
  }

ATOMICITY: The write-then-rename pattern ensures:
  - No partial files visible (temp → final is atomic on POSIX)
  - Concurrent writers: first rename wins, others see AlreadyExists
  - Content-addressable: same content → same filename → idempotent

V:TYPE — write_tx_file compiles
V:PROP — write same tx twice → second returns Ok (idempotent)
V:PROP — file content matches BLAKE3 hash in filename

[AUDIT-R3 MEDIUM FIX] Layout lifecycle operations.

  impl DiskLayout {
      /// Initialize a new braid store directory
      pub fn init(root: &Path) -> Result<Self, BraidError> {
          let store_dir = root.join('.braid');
          let tx_dir = store_dir.join('tx');
          let temp_dir = store_dir.join('tmp');

          std::fs::create_dir_all(&tx_dir)?;
          std::fs::create_dir_all(&temp_dir)?;

          // Write version marker
          std::fs::write(store_dir.join('VERSION'), '0.1.0')?;

          Ok(Self {
              config: LayoutConfig::default(),
              root: root.to_path_buf(),
          })
      }

      /// Load all transactions from disk into a Store
      pub fn load_all(&self) -> Result<Store, BraidError> {
          let mut store = Store::empty();  // no genesis — loaded from disk
          let tx_dir = self.root.join('.braid').join('tx');

          let mut entries: Vec<_> = std::fs::read_dir(&tx_dir)?
              .filter_map(|e| e.ok())
              .filter(|e| e.path().extension() == Some('edn'.as_ref()))
              .collect();

          // Sort by filename for deterministic load order
          entries.sort_by_key(|e| e.file_name());

          for entry in entries {
              let content = std::fs::read_to_string(entry.path())?;
              let datoms = parse_edn_datoms(&content)?;
              store.bulk_load(datoms);  // bypass transaction validation for loading
          }

          store.rebuild_indexes();
          Ok(store)
      }

      /// Verify integrity of on-disk store
      pub fn verify_integrity(&self) -> Result<IntegrityReport, BraidError> {
          let mut report = IntegrityReport::default();
          let tx_dir = self.root.join('.braid').join('tx');

          for entry in std::fs::read_dir(&tx_dir)? {
              let entry = entry?;
              let content = std::fs::read(&entry.path())?;
              let expected_hash = extract_hash_from_filename(&entry.file_name());
              let actual_hash = base58_encode(blake3::hash(&content).as_bytes());

              if expected_hash == actual_hash {
                  report.valid_files += 1;
              } else {
                  report.corrupted_files.push(entry.path());
              }
          }
          Ok(report)
      }
  }

V:TYPE — all three methods compile
V:PROP — load_all(init(dir)) returns genesis store (round-trip)
V:PROP — verify_integrity detects corrupted files

[AUDIT-R3 MEDIUM FIX] merge_directories specification.

Per spec/01b-storage-layout.md §1b.5:

  impl DiskLayout {
      /// Merge another store directory into this one (directory-level union)
      pub fn merge_directories(&self, other: &Path) -> Result<MergeOutcome, BraidError> {
          let other_tx_dir = other.join('.braid').join('tx');
          let our_tx_dir = self.root.join('.braid').join('tx');

          let mut new_files = 0usize;
          let mut dup_files = 0usize;

          for entry in std::fs::read_dir(&other_tx_dir)? {
              let entry = entry?;
              let dest = our_tx_dir.join(entry.file_name());

              if dest.exists() {
                  // Content-addressable: same filename = same content = duplicate
                  dup_files += 1;
              } else {
                  // Copy file (not move — preserve source)
                  std::fs::copy(entry.path(), &dest)?;
                  new_files += 1;
              }
          }

          // Reload to get the merged store
          let store = self.load_all()?;
          Ok(MergeOutcome {
              store,
              new_datoms: new_files,    // approximation: 1 file ≈ 1 tx
              duplicate_datoms: dup_files,
              cascade: MergeCascade::default(),
              schema_warnings: vec![],
          })
      }

      /// Rebuild in-memory cache from disk (recovery operation)
      pub fn rebuild_cache(&self) -> Result<Store, BraidError> {
          // Same as load_all but also verifies integrity
          let report = self.verify_integrity()?;
          if !report.corrupted_files.is_empty() {
              return Err(BraidError::Layout(LayoutError::Corruption {
                  files: report.corrupted_files,
              }));
          }
          self.load_all()
      }
  }

DIRECTORY MERGE = FILE COPY. This is the physical manifestation of the Store-Layout
isomorphism: merging stores at the algebraic level corresponds to copying files
at the filesystem level. Content-addressed naming makes this idempotent.

V:TYPE — merge_directories compiles
V:PROP — merge_directories is idempotent (second call adds 0 files)
V:PROP — merge_directories(A, B) then merge_directories(B, A) → same final state

