[AUDIT-R3 MEDIUM ADDENDUM] Stratum classifier implementation.

The stratum classifier analyzes a parsed Query and determines its stratum:

  pub fn classify_stratum(query: &Query) -> Stratum {
      let has_negation = query.where_clauses.iter().any(|c| matches!(c, Clause::Not(_) | Clause::NotJoin(..)));
      let has_aggregation = query.find.has_aggregates();
      let has_recursion = detect_recursion(&query.where_clauses);
      let has_external = query.where_clauses.iter().any(|c| matches!(c, Clause::Function(_)));

      match (has_negation, has_aggregation, has_recursion, has_external) {
          (false, false, _, false) => Stratum::S0_PureDatalog,
          (true, false, false, false) => Stratum::S1_StratifiedNegation,
          (_, true, false, false) => Stratum::S2_Aggregation,
          (true, _, true, false) => Stratum::S3_RecursiveNegation,
          (_, _, _, true) => Stratum::S4_ExternalPredicates,
          _ => Stratum::S3_RecursiveNegation, // conservative fallback
      }
  }

  fn detect_recursion(clauses: &[Clause]) -> bool {
      // Build predicate dependency graph, check for cycles via SCC
      let deps = build_predicate_deps(clauses);
      let sccs = tarjan_scc(&deps);
      sccs.iter().any(|scc| scc.len() > 1 || self_referential(scc))
  }

FRONTIER INTEGRATION: The frontier (AgentFrontier) can restrict query scope:
  pub fn query_with_frontier(
      store: &Store,
      query: &Query,
      frontier: Option<&AgentFrontier>,
  ) -> QueryResult {
      let view = match frontier {
          Some(f) => store.as_of(f.latest_known_tx()),
          None => store.current(),
      };
      evaluate(view, query)
  }

