  pub fn detect_gaps(
      store: &Store,
      session: &SessionState,
  ) -> Vec<EpistemicGap> {
      let mut gaps = Vec::new();

      // Strategy 1: Schema coverage — attributes used in session but not in schema
      for tx_id in &session.transactions {
          for datom in store.datoms_in_tx(tx_id) {
              if \!store.schema().has(&datom.attribute) {
                  gaps.push(EpistemicGap {
                      kind: EpistemicGapKind::UnrecordedSchema { attribute: datom.attribute.clone() },
                      confidence: 0.9,
                      source: GapSource::SessionLog,
                      suggested_action: GapAction::AddSchemaAttribute(
                          datom.attribute.clone(),
                          datom.value.value_type(),
                      ),
                  });
              }
          }
      }

      // Strategy 2: INV coverage — check for INVs without V:PROP tests
      let all_invs = store.query_inv_ids();
      let tested_invs = store.query_tested_inv_ids();
      for inv_id in all_invs.difference(&tested_invs) {
          gaps.push(EpistemicGap {
              kind: EpistemicGapKind::UntracedGoal { goal_ref: inv_id.clone() },
              confidence: 0.8,
              source: GapSource::StoreAnalysis,
              suggested_action: GapAction::CreateInvariant(format\!('Add test for {}', inv_id)),
          });
      }

      // Strategy 3: Decision detection — query results that imply a choice was made
      // (Heuristic: if a resolution mode was explicitly set during session, record as ADR)
      // This is Stage 0's simple gap detection. Stage 1+ adds FP/FN calibration.

      // Filter by confidence threshold
      gaps.retain(|g| g.confidence > 0.5);
      // Sort by confidence descending
      gaps.sort_by(|a, b| b.confidence.partial_cmp(&a.confidence).unwrap());
      gaps
  }

V:TYPE — detect_gaps compiles
V:PROP — empty session → empty gaps (no false positives from null input)
V:PROP — every returned gap has confidence > 0.5

